declare @c varchar(1024)
select @c = case @nh_theo when '0' then 'loai_vt' when '1' then 'nh_vt1' else '' end
if (@c = 'nh_vt1') and (cast(@tt_sx1 as tinyint) + cast(@tt_sx2 as tinyint) + cast(@tt_sx3 as tinyint) <> 0) begin
  select @c = @tt_sx1 + ',' + @tt_sx2 + ',' + @tt_sx3
  select @c = replace(replace(replace(@c, '1', 'nh_vt1'), '2', 'nh_vt2'), '3', 'nh_vt3')
  select @c = replace(replace(replace(@c, '0,', ''), ',0', ''), '0', '')
end

select cast(@den_ngay as smalldatetime) as date_to, @so_ngay as date_count
exec rs_rptStockBalanceSlow @den_ngay, @so_ngay, @ma_vt, @nh_vt1, @nh_vt2, @nh_vt3, @ma_dvcs, @c, 'ma_vt', @loai_du_lieu, @@language, @@userID, @@admin, '&Controller;', '@@sysDatabaseName', '#$query'






        /* <flatten type="Javascript"> */
var x = parseInt(this.getItemValue('tt_sx1')), y = parseInt(this.getItemValue('tt_sx2')), z = parseInt(this.getItemValue('tt_sx3'));
if ((x == y && x != 0) || (x == z && x != 0) || (y == z && y != 0)) {
  this._checked = false;
  $func.hideWait(this.get_id());
  $message.show(String.format($df.getResources(this._language, 'Message.RequiredField'), this.getItem('tt_sx1').field.Label), String.format('$find(\'{0}\').focus(\'{1}\');', this.get_id(), 'tt_sx1'));
}
