      /* <flatten type="Javascript"> */
function onChange$VoucherFilter$Tab(f, e) {f.parentForm.focusWhenTabChanged(['ma_vt', 'nh_theo']);}
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onChange$VoucherFilter$Tab);
  f._tabContainer._loaded = true;
  changeLookupReadonly(f, 'ma_dvcs');
  onchange$GroupBy(f.getItem('nh_theo'), true);
}
function close$VoucherFilter$(f) {
  try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}
  try {f._tabContainer.remove_activeTabChanged(onChange$VoucherFilter$Tab);} catch (ex) {}
}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, d2 = f.getItem('den_ngay').value, n = f.getItemValue('so_ngay'), x = f.getItemValue('mau_bc');
      g._alterTitle = [null, [['%d2', d2, true], ['%n', n, true]]];
      g._hiddenFields = [
        {Fields: 'tien', Value: (x == '10')},
        {Fields: 'tien_nt', Value: (x == '10' || x == '20')}
      ];
      if (f._hidden$GridForm) g._hiddenForms = [{Form: f._hidden$GridForm, Value: 1}];
      remove$GridReport$Filter(g);
      break;
    default:
      break;
  }
}
function onchange$GroupBy(o, force) {
  var f = o.parentForm, v = (f.getItemValue('nh_theo') != '1');
  f.getItem('tt_sx1').disabled = f.getItem('tt_sx3').disabled = f.getItem('tt_sx2').disabled = v;
  if (v && !force) {
    f.setItemValue('tt_sx1', 0);
    f.setItemValue('tt_sx2', 0);
    f.setItemValue('tt_sx3', 0);
  }
}/* </flatten> */




